const SYMBOLS  = ['✦','◈','◉','◎','▲','●','◆','▼'];
let selectedSwatch = 0;

document.getElementById('swatches').innerHTML = SWATCHES.map((c,i)=>
  `<div class="swatch${i===0?' selected':''}" style="background:${c}" onclick="pickSwatch(this,${i})"></div>`
).join('');

function pickSwatch(el,i){
  document.querySelectorAll('.swatch').forEach(x=>x.classList.remove('selected'));
  el.classList.add('selected'); selectedSwatch=i;
}

