// ── LANDING POSITIONS : natural scatter, avoids hero text zone (left 35%) ──
function getLandingPos(i, total) {
  const vw = window.innerWidth, vh = window.innerHeight;
  const CW = 196, CH = 230;
  // Divide canvas (excluding left 38%) into a loose grid, then nudge randomly
  const cols = 3, rows = Math.ceil(total / cols);
  const col = i % cols, row = Math.floor(i / cols);
  // Manual scatter positions as fractions of viewport : more organic, no grid
  const scatterOffsets = [
    { ox: 0.00, oy: 0.00 },
    { ox: 0.32, oy: -0.10 },
    { ox: 0.62, oy: 0.04 },
    { ox: 0.16, oy: 0.38 },
    { ox: 0.48, oy: 0.30 },
    { ox: 0.76, oy: 0.42 },
    { ox: 0.06, oy: 0.68 },
    { ox: 0.38, oy: 0.62 },
    { ox: 0.68, oy: 0.72 },
  ];
  const off = scatterOffsets[i % scatterOffsets.length];
  const safeLeft = vw * 0.44;
  const availW = vw - safeLeft - CW - 40;
  const availH = vh - 110 - CH;
  const jx = (Math.random() - 0.5) * 30;
  const jy = (Math.random() - 0.5) * 24;
  return {
    x: Math.max(safeLeft, Math.min(vw - CW - 8, safeLeft + off.ox * availW + jx)),
    y: Math.max(140, Math.min(vh - CH - 10, 140 + off.oy * availH + jy))
  };
}

// Build DOM for a card (invisible initially)
function buildCard(data, id, pos) {
  // More varied rotations : each card gets a wider, more organic angle
  const rotOptions = [-11, 6, -4, 9, -7, 13, -2, 8, -13, 5, -9, 3];
  const rot = rotOptions[id % rotOptions.length] + (Math.random() * 4 - 2);
  const card = document.createElement('div');
  card.className = 'card';
  card.dataset.id = id;

  // Start off-screen bottom with stronger rotation
  const startRot = rot + (Math.random() > 0.5 ? 10 : -10);
  card.style.cssText = `left:${pos.x}px;top:${pos.y}px;transform:rotate(${startRot}deg) translateY(40px);z-index:${10+id}`;

  const hasLink = data.url && data.url !== '#';
  const sym = SYMBOLS[id % SYMBOLS.length];
  const bg  = data.color || '#f5f0e8';
  const thumb = data.img
    ? `<img src="${data.img}" style="width:100%;height:100%;object-fit:cover;display:block">`
    : `<span style="font-size:48px;opacity:0.35;line-height:1">${sym}</span>`;

  card.innerHTML = `
    <div class="card-inner">
      <div class="card-thumb">
        <div class="card-thumb-bg" style="background:${bg}">${thumb}</div>
        <div class="card-link-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="#111827" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/>
            <polyline points="15 3 21 3 21 9"/>
            <line x1="10" y1="14" x2="21" y2="3"/>
          </svg>
        </div>
      </div>
      <div class="card-stub">
        <div class="card-stub-title">${data.title}</div>
        <div class="card-stub-tag">${data.tag||''}</div>
      </div>
    </div>`;

  // Animate in: fade + settle rotation
  card._landRot = rot;
  card._startRot = startRot;

  // Drag
  let sx, sy, sl, st, didDrag = false;
  card.addEventListener('mousedown', e => {
    e.preventDefault();
    didDrag = false;
    sx = e.clientX; sy = e.clientY;
    sl = parseInt(card.style.left); st = parseInt(card.style.top);
    document.querySelectorAll('.card').forEach(c=>{ if(c!==card) c.style.zIndex=10; });
    card.style.zIndex=1000;
    card.style.transition='box-shadow 0.2s ease';

    const onMove = me => {
      const dx = me.clientX-sx, dy = me.clientY-sy;
      if(!didDrag && (Math.abs(dx)>4||Math.abs(dy)>4)){
        didDrag=true; card.classList.add('dragging');
      }
      if(didDrag){
        card.style.left=(sl+dx)+'px';
        card.style.top=(st+dy)+'px';
      }
    };
    const onUp = ()=>{
      card.classList.remove('dragging');
      card.style.transition='box-shadow 0.2s ease';
      document.removeEventListener('mousemove',onMove);
      document.removeEventListener('mouseup',onUp);
      if(!didDrag && hasLink) window.open(data.url,'_blank');
    };
    document.addEventListener('mousemove',onMove);
    document.addEventListener('mouseup',onUp);
  });

  return card;
}

// ── DEAL ENGINE ──
const canvas = document.getElementById('canvas');
const hint   = document.getElementById('hint');
const progress = document.getElementById('progress');

// Pre-build all cards with positions, but keep invisible
const positions = ARTICLES.map((_, i) => getLandingPos(i, ARTICLES.length));
const cardEls   = ARTICLES.map((data, i) => {
  const card = buildCard(data, i, positions[i]);
  canvas.appendChild(card);
  return card;
});

let dealtCount = 0;
const total = ARTICLES.length;

function dealNext() {
  if (dealtCount >= total) return;
  const card = cardEls[dealtCount];
  dealtCount++;

  // Trigger fade + settle animation via inline transition
  card.style.transition = 'opacity 0.5s ease, transform 0.55s cubic-bezier(0.22,1,0.36,1)';
  card.style.opacity = '1';
  card.style.transform = `rotate(${card._landRot}deg) translateY(0)`;

  setTimeout(() => {
    card.classList.add('landed');
    card.style.transition = 'box-shadow 0.2s ease';
  }, 560);

  // Update progress
  progress.textContent = `${dealtCount} / ${total}`;

  // Hide hint after first deal
  if (dealtCount === 1) hint.classList.add('hidden');

  // Hide progress when all dealt
  if (dealtCount === total) {
    setTimeout(() => progress.style.opacity = '0', 1200);
  }
}

// ── SCROLL / WHEEL LISTENER ──
let scrollAccum = 0;
const SCROLL_THRESH = 60; // px of scroll per card

window.addEventListener('wheel', e => {
  // Only intercept scroll for card dealing while we're at the top (canvas visible)
  if (window.scrollY > 10) return; // let normal scroll take over once past canvas
  if (dealtCount >= total) return; // all dealt : let page scroll naturally to projects
  e.preventDefault();
  scrollAccum += Math.abs(e.deltaY);
  if (scrollAccum >= SCROLL_THRESH) {
    scrollAccum = 0;
    dealNext();
  }
}, { passive: false });

// Touch swipe up to deal
let touchStartY = 0;
window.addEventListener('touchstart', e => { touchStartY = e.touches[0].clientY; }, { passive:true });
window.addEventListener('touchmove', e => {
  if (dealtCount >= total) return;
  const dy = touchStartY - e.touches[0].clientY;
  if (dy > 30) { touchStartY = e.touches[0].clientY; dealNext(); }
}, { passive:true });

// Panel
function openPanel(){
  document.getElementById('panel').classList.add('open');
  document.getElementById('overlay').classList.add('open');
}
function closePanel(){
  document.getElementById('panel').classList.remove('open');
  document.getElementById('overlay').classList.remove('open');
}
function addCard(){
  const title = document.getElementById('f-title').value.trim();
  const url   = document.getElementById('f-url').value.trim();
  const tag   = document.getElementById('f-tag').value.trim();
  if(!title){ document.getElementById('f-title').focus(); return; }

  const id = cardEls.length;
  const pos = {
    x: Math.random()*(window.innerWidth*0.55)+window.innerWidth*0.38,
    y: Math.random()*(window.innerHeight-280)+60
  };
  const data = { title, url:url||'#', tag, color:SWATCHES[selectedSwatch] };
  const card = buildCard(data, id, pos);
  canvas.appendChild(card);
  cardEls.push(card);

  // Immediately deal it
  requestAnimationFrame(()=>{
    card.style.transition='opacity 0.5s ease, transform 0.55s cubic-bezier(0.22,1,0.36,1)';
    card.style.opacity='1';
    card.style.transform=`rotate(${card._landRot}deg) translateY(0)`;
    setTimeout(()=>{ card.classList.add('landed'); card.style.transition='box-shadow 0.2s ease'; },560);
  });

  ['f-title','f-url','f-tag'].forEach(id=>document.getElementById(id).value='');
  closePanel();
}
